;-------------------------------------------------------------------------------
; マップを開いた時に必ず実行されるスクリプト
[initial]

[endinitial]
;===============================================================================
;◆イベント◆

; 初期発生イベント
events = [1, 2]

;-------------------------------------------------------------------------------
*event_1
;[exp] onObjectTrigger

@barrel
@damage v=&'game.curTarget.addParam("power", 1)'
@notice text=&'"<p>" + game.curTarget.displayName + "<w> had Strength permanently increased by 1!"'

[eventoff]
;-------------------------------------------------------------------------------
*event_2
;[exp] onObjectTrigger

@barrel anime=*barrel_poison
@eval exp='game.curTarget.setStatus(o.毒, true)'
@notice text=&'"<p>" + game.curTarget.displayName + "<w> is poisoned!"'

[eventoff]
;-------------------------------------------------------------------------------
